// Log swarm results
const d = $input.first().json;
const rows = (d.predictions || []).map(p => {
  const pct = p.swarm_risk_probability != null ? (p.swarm_risk_probability * 100).toFixed(1) + '%' : (p.error || '?');
  return `  Hive ${String(p.box_id).padStart(2)}: ${(p.risk_level || 'UNKNOWN').padEnd(10)} ${pct}`;
}).join('\n');
console.log(`[SwarmRisk ${d.run_date}] ${d.alert_count} alertas\n${rows}`);
return $input.all();

// Log alza update
const d = $input.first().json;
const dates = d.last_date_per_hive || {};
const lines = Object.entries(dates).map(([h,dt]) => `  Hive ${h}: ${dt}`).join('\n');
console.log(`[AlzaUpdate ${d.run_date}] status=${d.status} | rows=${d.total_feat_rows} | elapsed=${d.elapsed_s}s\nLatest dates per hive:\n${lines}`);
return $input.all();

// Build alert message
const d = $input.first().json;
const lines = (d.alerts || []).map(a => {
  const pct = a.swarm_risk_probability != null ? (a.swarm_risk_probability * 100).toFixed(1) + '%' : '';
  return `COLMENA ${a.box_id}: ${pct} riesgo en los proximos 3 dias`;
});
const message = [
  `[${d.run_date}] ALERTA ENJAMBRAZON — ${d.alert_count} colmena(s) en riesgo ALTO:`,
  ...lines,
  `Total colmenas analizadas: ${(d.hives || []).length}`
].join('\n');
console.log(message);
return [{ json: { message, alert_count: d.alert_count, run_date: d.run_date, alerts: d.alerts } }];
